-- creationforge.lua — Lua raw-gen port of The Creation Forge reactions.
--
-- WHY THIS EXISTS
--   The static mod hand-maintained two huge files that must stay in lockstep:
--     objects/reaction_custom_creationforge.txt   (6,979 lines / 910 reactions)
--     objects/entity_patch_creationforge.txt       (1 MB / 22,510 PERMITTED_REACTION lines,
--                                                    plus commented per-mod compat blocks)
--   This script regenerates the reactions from compact data tables instead. Each reaction is
--   emitted with [FORTRESS_MODE_ENABLED], which makes it usable by ANY fortress civ WITHOUT a
--   [PERMITTED_REACTION] entry. That deletes the entire reaction-permit half of the entity patch
--   and the per-mod uncommenting chore — the reactions now work for every civ/mod automatically.
--
-- WHAT STAYS STATIC (buildings can't be Lua-generated, not in the gen scope)
--   objects/building_custom_creationforge.txt        — the two workshops
--   graphics/*                                        — workshop sprites
--   objects/material_template_patch_creationforge.txt — dragon-scale -> leather
--   A SLIM entity patch granting only [PERMITTED_BUILDING] for the two workshops
--   (see objects/entity_patch_creationforge_SLIM.txt). One permit per civ; no reactions.
--
-- PORT STATUS  (see scripts/README_LUA_PORT.md)
--   DONE here: Wood (84), Cloth/Thread/Leather (17), all Training (137) = 238 reactions.
--   TODO: the remaining ~672 reactions (containers, weapons, armor, food, blocks, metals, gems,
--   furniture, tools, clothing, ...). They use the SAME emit{} helper — add data tables below.
--   Until the port is complete, do NOT load both this script and the static reaction file:
--   duplicate [REACTION] ids will error at worldgen.

do_once.creationforge = function()
	-- Custom tableware item definitions -- DF vanilla has no bowl or plate. Registered as item
	-- raws so the reactions below can make them. (Items are in Lua-gen scope; buildings are not.)
	local items = {}
	local function itemdef(id, body)
		items[#items+1] = "[ITEM_TOOL:" .. id .. "]"
		add_generated_info(items)
		for _, l in ipairs(body) do items[#items+1] = l end
	end
	itemdef("ITEM_TOOL_BOWL",  { "[NAME:bowl:bowls]",  "[VALUE:5]", "[TILE:7]",   "[SIZE:100]", "[TOOL_USE:LIQUID_CONTAINER]", "[TOOL_USE:FOOD_STORAGE]", "[HARD_MAT]" })
	-- ITEM_TOOL_PLATE is custom -> defined statically in objects/item_creationforge_items.txt so DF's
	-- graphics loader can bind its sprite. (BOWL is a vanilla item and keeps its vanilla sprite.)
	raws.register_items(items)

	local out = {}            -- accumulated reaction raw lines
	local declared = {}       -- categories already given NAME/PARENT

	-- Full submenu tree: { id, display_name, parent(optional) }. Order matches the static mod.
	local CATS = {
		{"PLANTSSEEDS","Plants and seeds"},
		{"RAW_PLANTS","Plants","PLANTSSEEDS"},
		{"SEEDS","Seeds","PLANTSSEEDS"},
		{"WOOD","Wood"},
		{"CLOTHLEATHER","Cloth and leather"},
		{"CLOTH","Cloth and thread","CLOTHLEATHER"},
		{"LEATHER","Leather","CLOTHLEATHER"},
		{"CONTAINERS","Containers"},
		{"JUGS","Jugs","CONTAINERS"},
		{"BAGS","Bags","CONTAINERS"},
		{"BARRELS","Barrels","CONTAINERS"},
		{"BUCKETS","Buckets","CONTAINERS"},
		{"BINS","Bins","CONTAINERS"},
		{"BOXES","Chests","CONTAINERS"},
		{"VIALS","Flasks and vials","CONTAINERS"},
		{"BACKPACKS","Backpacks","CONTAINERS"},
		{"ARMORWEAPONS","Armor and weapons"},
		{"AMMUNITION","Ammunition and quivers","ARMORWEAPONS"},
		{"WEAPONS","Weapons","ARMORWEAPONS"},
		{"ADAMANTINEWEAPONS","Adamantine weapons","WEAPONS"},
		{"STEELWEAPONS","Steel weapons","WEAPONS"},
		{"IRONWEAPONS","Iron weapons","WEAPONS"},
		{"OTHERWEAPONS","Other materials","WEAPONS"},
		{"TRAININGWEAPONS","Training weapons","WEAPONS"},
		{"COPPERWEAPONS","Copper weapons","WEAPONS"},
		{"BRONZEWEAPONS","Bronze weapons","WEAPONS"},
		{"BISMUTHBRONZEWEAPONS","Bismuth bronze weapons","WEAPONS"},
		{"ARMOR","Armor","ARMORWEAPONS"},
		{"ADAMANTINEARMOR","Adamantine armor","ARMOR"},
		{"STEELARMOR","Steel armor","ARMOR"},
		{"IRONARMOR","Iron armor","ARMOR"},
		{"UNICORNARMOR","Unicorn leather armor","ARMOR"},
		{"LEATHERARMOR","Leather armor","ARMOR"},
		{"ARMORSETS","Armor sets","ARMOR"},
		{"COPPERARMOR","Copper armor","ARMOR"},
		{"BRONZEARMOR","Bronze armor","ARMOR"},
		{"BISMUTHBRONZEARMOR","Bismuth bronze armor","ARMOR"},
		{"FOODDRINKS","Food and drinks"},
		{"FOOD","Food","FOODDRINKS"},
		{"FISH","Fish","FOODDRINKS"},
		{"DRINKS","Drinks","FOODDRINKS"},
		{"PAPER","Writing"},
		{"MISC","Miscellaneous"},
		{"BLOCKSBRICKS","Blocks and stones"},
		{"BLOCKS","Blocks","BLOCKSBRICKS"},
		{"ECON_STN","Stones","BLOCKSBRICKS"},
		{"SANDCLAY","Sand and Clay","BLOCKSBRICKS"},
		{"ADAM","Adamantine"},
		{"METALSALLOYS","Metals and alloys"},
		{"ALLOYS","Alloys","METALSALLOYS"},
		{"METAL_BARS","Metals","METALSALLOYS"},
		{"VALUABLE_ORE","Valuable ore","METALSALLOYS"},
		{"GEMGLASS","Gemstones and glass"},
		{"GLASS","Glass","GEMGLASS"},
		{"RGEMS","Rough gemstones","GEMGLASS"},
		{"CGEMS","Cut gemstones","GEMGLASS"},
		{"FURNITURE","Furniture"},
		{"FURNITURESET","Furniture sets","FURNITURE"},
		{"WOODFURNITURE","Feather wood","FURNITURE"},
		{"ADAMFURNITURE","Adamantine","FURNITURE"},
		{"GLASSFURNITURE","Crystal glass","FURNITURE"},
		{"MARBLEFURNITURE","Marble","FURNITURE"},
		{"TOOLSTRAPS","Tools and traps"},
