		{"LEATHER_CLOTHES","Leather clothes","CLOTHING"},
		{"DRAGONSCALE_CLOTHES","Dragon scale clothes","CLOTHING"},
		{"CLOTHINGSET","Clothing sets","CLOTHING"},
		{"COMBAT_SKILL","Combat Skills Training"},
		{"SOC_SKILL","Social Skills Training"},
		{"OTHER_SKILL","Other Skills Training"},
		{"LABOR_SKILL","Labor Skills Training"},
	}
	local catinfo = {}
	for _, c in ipairs(CATS) do catinfo[c[1]] = c end

	-- Declare a category (and its ancestors) the first time it is used, mirroring the static mod
	-- where the first reaction in a submenu carries its [CATEGORY_NAME]/[CATEGORY_PARENT].
	local function declare(cid)
		if declared[cid] then return end
		declared[cid] = true
		local c = catinfo[cid]
		if c and c[3] then declare(c[3]) end            -- parent first
		out[#out+1] = "[CATEGORY:" .. cid .. "]"
		if c and c[2] then out[#out+1] = "[CATEGORY_NAME:" .. c[2] .. "]" end
		if c and c[3] then out[#out+1] = "[CATEGORY_PARENT:" .. c[3] .. "]" end
	end

	-- Emit one reaction.
	--   r.id      reaction id              r.skill  job skill token
	--   r.name    in-game name             r.ip     training: SKILL_IP + ATTRIBUTE_IP value
	--   r.build   building (default CREATION_FORGE)
	--   r.cat     submenu id
	--   r.reagents { "A:1:BARREL:NONE:NONE:NONE|EMPTY|PRESERVE_REAGENT|..." }  ('|' -> token break)
	--   r.prods    { "100:10:WOOD:NONE:PLANT_MAT:OAK:WOOD",                    -- simple product
	--               { "100:10:CLOTH:NONE:CREATURE_MAT:ALPACA:HAIR", dim=10000, to="A" } }
	local function emit(r)
		out[#out+1] = "[REACTION:" .. r.id .. "]"
		add_generated_info(out)
		out[#out+1] = "[NAME:" .. r.name .. "]"
		out[#out+1] = "[BUILDING:" .. (r.build or "CREATION_FORGE") .. ":NONE]"
		out[#out+1] = "[FORTRESS_MODE_ENABLED]"
		for _, rg in ipairs(r.reagents or {}) do
			out[#out+1] = "[REAGENT:" .. rg:gsub("|", "][") .. "]"
		end
		for _, p in ipairs(r.prods or {}) do
			if type(p) == "table" then
				out[#out+1] = "[PRODUCT:" .. p[1] .. "]"
				-- p.mods = ordered raw modifier tokens (preserves original order); used by
				-- creationforge_extra.lua. p.dim/p.to/p.flags are the convenience form for the loops.
				for _, m in ipairs(p.mods or {}) do out[#out+1] = "[" .. m .. "]" end
				if p.dim then out[#out+1] = "[PRODUCT_DIMENSION:" .. p.dim .. "]" end
				if p.to  then out[#out+1] = "[PRODUCT_TO_CONTAINER:" .. p.to .. "]" end
				for _, f in ipairs(p.flags or {}) do out[#out+1] = "[" .. f .. "]" end
			else
				out[#out+1] = "[PRODUCT:" .. p .. "]"
			end
		end
		if r.skill then out[#out+1] = "[SKILL:" .. r.skill .. "]" end
		if r.ip then
			out[#out+1] = "[SKILL_IP:" .. r.ip .. "]"
			out[#out+1] = "[ATTRIBUTE_IP:" .. r.ip .. "]"
		end
		if r.cat then declare(r.cat); out[#out+1] = "[CATEGORY:" .. r.cat .. "]" end
	end

