		{"NETHER_CAP","nether-cap logs (dark indigo)"}, {"TUNNEL_TUBE","tunnel tube logs (violet)"},
		{"FUNGIWOOD","fungiwood logs (lemon)"}, {"SPORE_TREE","spore tree logs (teal)"},
		{"PAPAYA","papaya logs (taupe pale)"}, {"CANDLENUT","candlenut logs (ochre)"},
		{"WILLOW","willow logs (tan)"}, {"CHERRY","cherry logs (gold)"},
		{"CACAO","cacao logs (chocolate)"}, {"CHESTNUT","chestnut logs (dark chestnut)"},
		{"SAGUARO","saguaro logs (ecru)"}, {"GINKGO","ginkgo logs (peach)"},
		{"RUBBER","rubber logs (flax)"}, {"HIGHWOOD","highwood logs (brown)"},
		{"PINE","pine logs (beige)"}, {"DURIAN","durian logs (taupe pale)"},
		{"MANGO","mango logs (burnt sienna)"}, {"AVOCADO","avocado logs (chestnut)"},
		{"MAPLE","maple logs (rust)"}, {"CARAMBOLA","carambola logs (flax)"},
		{"TEA","tea logs (taupe pale)"}, {"WALNUT","walnut logs (dark tan)"},
		{"CEDAR","cedar logs (olive)"}, {"LARCH","larch logs (light brown)"},
		{"POMELO","pomelo logs (ash gray)"}, {"ACACIA","acacia logs (peach)"},
		{"ASH","ash logs (pale brown)"}, {"MAHOGANY","mahogany logs (mahogany)"},
		{"PEAR","pear logs (buff)"}, {"RAMBUTAN","rambutan logs (bronze)"},
		{"BIRCH","birch logs (burnt umber)"}, {"PALM","palm logs (dark taupe)"},
		{"CITRON","citron logs (ash gray)"}, {"OAK","oak logs (auburn)"},
		{"ALMOND","almond logs (copper)"}, {"LYCHEE","lychee logs (taupe sandy)"},
	}
	for _, qty in ipairs({10, 100}) do          -- static mod lists all x10, then all x100
		for _, w in ipairs(WOODS) do
			emit{ id = "FREE_WOOD_" .. w[1] .. "_" .. qty,
			      name = "make " .. qty .. " " .. w[2],
			      skill = "WOODCUTTING", cat = "WOOD",
			      prods = { "100:" .. qty .. ":WOOD:NONE:PLANT_MAT:" .. w[1] .. ":WOOD" } }
		end
	end

	----------------------------------------------------- CLOTH / THREAD / LEATHER (17)
