		{"FREE_CLOTH_WOOL_10","make 10 wool cloth","CLOTHESMAKING","CLOTH","100:10:CLOTH:NONE:CREATURE_MAT:ALPACA:HAIR",10000},
		{"FREE_CLOTH_PLANT_10","make 10 plant cloth","CLOTHESMAKING","CLOTH","100:10:CLOTH:NONE:PLANT_MAT:GRASS_TAIL_PIG:THREAD",10000},
		{"FREE_CLOTH_SILK_100","make 100 silk cloth","CLOTHESMAKING","CLOTH","100:100:CLOTH:NONE:CREATURE_MAT:SPIDER_CAVE_GIANT:SILK",10000},
		{"FREE_CLOTH_WOOL_100","make 100 wool cloth","CLOTHESMAKING","CLOTH","100:100:CLOTH:NONE:CREATURE_MAT:ALPACA:HAIR",10000},
		{"FREE_CLOTH_PLANT_100","make 100 plant cloth","CLOTHESMAKING","CLOTH","100:100:CLOTH:NONE:PLANT_MAT:GRASS_TAIL_PIG:THREAD",10000},
		{"FREE_THREAD_PLANT_10","make 10 plant thread","SPINNING","CLOTH","100:10:THREAD:NONE:PLANT_MAT:GRASS_TAIL_PIG:THREAD",15000},
		{"FREE_THREAD_SILK_10","make 10 silk thread","SPINNING","CLOTH","100:10:THREAD:NONE:CREATURE_MAT:SPIDER_CAVE_GIANT:SILK",15000},
		{"FREE_THREAD_WOOL_10","make 10 wool thread","SPINNING","CLOTH","100:10:THREAD:NONE:CREATURE_MAT:ALPACA:HAIR",15000},
		{"FREE_THREAD_PLANT_100","make 100 plant thread","SPINNING","CLOTH","100:100:THREAD:NONE:PLANT_MAT:GRASS_TAIL_PIG:THREAD",15000},
		{"FREE_THREAD_SILK_100","make 100 silk thread","SPINNING","CLOTH","100:100:THREAD:NONE:CREATURE_MAT:SPIDER_CAVE_GIANT:SILK",15000},
		{"FREE_THREAD_WOOL_100","make 100 wool thread","SPINNING","CLOTH","100:100:THREAD:NONE:CREATURE_MAT:ALPACA:HAIR",15000},
		{"FREE_LEATHER_COW_10","make 10 cow leather","LEATHERWORK","LEATHER","100:10:SKIN_TANNED:NONE:CREATURE_MAT:COW:LEATHER"},
		{"FREE_LEATHER_COW_100","make 100 cow leather","LEATHERWORK","LEATHER","100:100:SKIN_TANNED:NONE:CREATURE_MAT:COW:LEATHER"},
		{"FREE_LEATHER_DRAGON_10","make 10 dragon scale leather","LEATHERWORK","LEATHER","100:10:SKIN_TANNED:NONE:CREATURE_MAT:DRAGON:SCALE"},
		{"FREE_LEATHER_DRAGON_100","make 100 dragon scale leather","LEATHERWORK","LEATHER","100:100:SKIN_TANNED:NONE:CREATURE_MAT:DRAGON:SCALE"},
		{"FREE_LEATHER_UNICORN_10","make 10 unicorn leather","LEATHERWORK","LEATHER","100:10:SKIN_TANNED:NONE:CREATURE_MAT:UNICORN:LEATHER"},
		{"FREE_LEATHER_UNICORN_100","make 100 unicorn leather","LEATHERWORK","LEATHER","100:100:SKIN_TANNED:NONE:CREATURE_MAT:UNICORN:LEATHER"},
	}
	for _, r in ipairs(CL) do
		emit{ id = r[1], name = r[2], skill = r[3], cat = r[4],
		      prods = { { r[5], dim = r[6] } } }
	end

	-------------------------------------------------------------- TRAINING (137)
	-- { submenu, skill, role-name }. Each grants SKILL_IP + ATTRIBUTE_IP = 5000 (~100x normal).
